package com.sundev.sunpaste;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;

@SpringBootApplication
public class Main {
    /**
     * The main entry point for the Spring Boot application.
     * This method bootstraps the application by invoking SpringApplication.run().
     * @param args command line arguments
     */
    public static void main(String[] args) {
            SpringApplication.run(Main.class, args);
    }
}

/**
 * highlightjs-code.js
 *
 * Vaadin Flow client-side web component wrapping highlight.js.
 * Located in: src/main/resources/META-INF/resources/frontend/
 *
 * The @JsModule annotation in HighlightJs.java points here.
 */

import { LitElement, html, css } from 'lit';
import hljs from 'highlight.js';

class HighlightjsCode extends LitElement {

  static get properties() {
    return {
      /** Raw source code to highlight */
      code: { type: String },

      /** Language key, e.g. "java", "python", "auto" */
      language: { type: String },

      /** highlight.js theme CSS name, e.g. "github-dark", "monokai" */
      theme: { type: String },

      /** Whether to show gutter line numbers */
      showLineNumbers: { type: Boolean },

      /** Whether to show the detected/set language badge */
      showLanguageBadge: { type: Boolean },

      /** Whether to show a copy-to-clipboard button */
      showCopyButton: { type: Boolean },

      /** Optional filename label shown in the header bar */
      filename: { type: String },

      /** Internal: detected language name after highlighting */
      _detectedLanguage: { type: String, state: true },

      /** Internal: tracks copy button state */
      _copied: { type: Boolean, state: true },
    };
  }

  constructor() {
    super();
    this.code = '';
    this.language = 'auto';
    this.theme = 'github-dark';
    this.showLineNumbers = false;
    this.showLanguageBadge = true;
    this.showCopyButton = true;
    this.filename = '';
    this._detectedLanguage = '';
    this._copied = false;
    this._themeLink = null;
  }

  // -------------------------------------------------------------------------
  // Lifecycle
  // -------------------------------------------------------------------------

  connectedCallback() {
    super.connectedCallback();
    this._loadTheme(this.theme);
  }

  updated(changedProps) {
    if (changedProps.has('theme')) {
      this._loadTheme(this.theme);
    }
  }

  // -------------------------------------------------------------------------
  // Theme loading  — injects a <link> into the shadow root
  // -------------------------------------------------------------------------

  _loadTheme(themeName) {
    // Remove old theme link if present
    if (this._themeLink) {
      this._themeLink.remove();
      this._themeLink = null;
    }

    const link = document.createElement('link');
    link.rel = 'stylesheet';
    // highlight.js ships CSS under highlight.js/styles/
    link.href = `https://cdnjs.cloudflare.com/ajax/libs/highlight.js/11.9.0/styles/${themeName}.min.css`;

    // Wait until the root is available
    if (this.shadowRoot) {
      this.shadowRoot.appendChild(link);
    } else {
      this.updateComplete.then(() => {
        this.shadowRoot.appendChild(link);
      });
    }
    this._themeLink = link;
  }

  // -------------------------------------------------------------------------
  // Syntax highlighting
  // -------------------------------------------------------------------------

  _highlight() {
    if (!this.code) return { value: '', language: '' };

    if (this.language && this.language !== 'auto') {
      try {
        const result = hljs.highlight(this.code, { language: this.language });
        return { value: result.value, language: result.language };
      } catch (e) {
        // Unknown language — fall back to auto-detect
      }
    }

    const result = hljs.highlightAuto(this.code);
    return { value: result.value, language: result.language };
  }

  _buildLines(highlightedHtml) {
    if (!this.showLineNumbers) return highlightedHtml;

    const lines = highlightedHtml.split('\n');
    return lines
      .map((line, i) =>
        `<span class="line-number">${i + 1}</span>${line}`
      )
      .join('\n');
  }

  // -------------------------------------------------------------------------
  // Copy to clipboard
  // -------------------------------------------------------------------------

  async _copyCode() {
    try {
      await navigator.clipboard.writeText(this.code);
      this._copied = true;
      setTimeout(() => { this._copied = false; }, 2000);
    } catch (e) {
      console.warn('highlightjs-code: clipboard write failed', e);
    }
  }

  // -------------------------------------------------------------------------
  // Styles
  // -------------------------------------------------------------------------

  static get styles() {
    return css`
      :host {
        display: block;
        border-radius: 8px;
        overflow: hidden;
        font-family: 'JetBrains Mono', 'Fira Code', 'Cascadia Code', monospace;
        font-size: 0.875rem;
        line-height: 1.6;
        box-shadow: 0 4px 24px rgba(0,0,0,0.18);
      }

      /* ---- Header bar ---- */
      .header {
        display: flex;
        align-items: center;
        justify-content: space-between;
        padding: 8px 14px;
        background: rgba(0,0,0,0.25);
        backdrop-filter: blur(4px);
        gap: 8px;
        min-height: 36px;
      }

      .header-left {
        display: flex;
        align-items: center;
        gap: 8px;
      }

      /* macOS-style traffic lights (decorative) */
      .dots {
        display: flex;
        gap: 6px;
      }
      .dot {
        width: 12px;
        height: 12px;
        border-radius: 50%;
      }
      .dot-red    { background: #ff5f57; }
      .dot-yellow { background: #ffbd2e; }
      .dot-green  { background: #28c840; }

      .filename {
        font-size: 0.78rem;
        opacity: 0.7;
        letter-spacing: 0.02em;
        color: inherit;
      }

      .header-right {
        display: flex;
        align-items: center;
        gap: 8px;
      }

      .language-badge {
        font-size: 0.7rem;
        text-transform: uppercase;
        letter-spacing: 0.08em;
        opacity: 0.6;
        padding: 2px 7px;
        border: 1px solid currentColor;
        border-radius: 4px;
      }

      .copy-btn {
        background: none;
        border: 1px solid rgba(255,255,255,0.25);
        border-radius: 5px;
        color: inherit;
        cursor: pointer;
        font-size: 0.72rem;
        padding: 3px 9px;
        opacity: 0.7;
        transition: opacity 0.15s, background 0.15s;
        display: flex;
        align-items: center;
        gap: 5px;
      }
      .copy-btn:hover { opacity: 1; background: rgba(255,255,255,0.1); }
      .copy-btn.copied { opacity: 1; border-color: #4ade80; color: #4ade80; }

      /* ---- Code area ---- */
      .code-wrapper {
        overflow: auto;
      }

      pre {
        margin: 0;
        padding: 18px;
        line-height: 1.5;
      }

      code {
        font-family: inherit;
      }

      /* Line number gutter */
      .line-number {
        display: inline-block;
        user-select: none;
        min-width: 2.5em;
        text-align: right;
        opacity: 0.4;
        margin-right: 16px;
        color: inherit;
      }
    `;
  }

  // -------------------------------------------------------------------------
  // Render
  // -------------------------------------------------------------------------

  render() {
    const { value: highlighted, language: detectedLang } = this._highlight();
    const lang = detectedLang || this.language || '';
    const body = this._buildLines(highlighted);
    const hasHeader = this.filename || this.showLanguageBadge || this.showCopyButton;

    return html`
      ${hasHeader ? html`
        <div class="header">
          <div class="header-left">
            <div class="dots">
              <div class="dot dot-red"></div>
              <div class="dot dot-yellow"></div>
              <div class="dot dot-green"></div>
            </div>
            ${this.filename ? html`<span class="filename">${this.filename}</span>` : ''}
          </div>
          <div class="header-right">
            ${this.showLanguageBadge && lang ? html`
              <span class="language-badge">${lang}</span>
            ` : ''}
            ${this.showCopyButton ? html`
              <button
                class="copy-btn ${this._copied ? 'copied' : ''}"
                @click="${this._copyCode}"
                title="Copy to clipboard"
              >
                ${this._copied
                  ? html`<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="20 6 9 17 4 12"/></svg> Copied`
                  : html`<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="9" y="9" width="13" height="13" rx="2"/><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/></svg> Copy`
                }
              </button>
            ` : ''}
          </div>
        </div>
      ` : ''}

      <div class="code-wrapper">
        <pre><code class="hljs" .innerHTML="${body}"></code></pre>
      </div>
    `;
  }
}

customElements.define('highlightjs-code', HighlightjsCode);

/**
 * highlightjs-code.js
 *
 * Vaadin Flow client-side web component wrapping highlight.js.
 * Located in: src/main/resources/META-INF/resources/frontend/
 *
 * The @JsModule annotation in HighlightJs.java points here.
 */

import { LitElement, html, css } from 'lit';
import hljs from 'highlight.js';
import beautify from 'js-beautify';

class HighlightjsCode extends LitElement {

  static get properties() {
    return {
      /** Raw source code to highlight */
      code: { type: String },

      /** Language key, e.g. "java", "python", "auto" */
      language: { type: String },

      /** highlight.js theme CSS name, e.g. "github-dark", "monokai" */
      theme: { type: String },

      /** Whether to show gutter line numbers */
      showLineNumbers: { type: Boolean },

      /** Whether to show the detected/set language badge */
      showLanguageBadge: { type: Boolean },

      /** Whether to show a copy-to-clipboard button */
      showCopyButton: { type: Boolean },

      /** Optional filename label shown in the header bar */
      filename: { type: String },

      /** Whether to attempt auto-formatting/beautifying the code */
      formatCode: { type: Boolean },

      /** Internal: detected language name after highlighting */
      _detectedLanguage: { type: String, state: true },

      /** Internal: tracks copy button state */
      _copied: { type: Boolean, state: true },
    };
  }

  constructor() {
    super();
    this.code = '';
    this.language = 'auto';
    this.theme = 'github-dark';
    this.showLineNumbers = false;
    this.showLanguageBadge = true;
    this.showCopyButton = true;
    this.filename = '';
    this.formatCode = false;
    this._detectedLanguage = '';
    this._copied = false;
    this._themeLink = null;
  }

  // -------------------------------------------------------------------------
  // Lifecycle
  // -------------------------------------------------------------------------

  connectedCallback() {
    super.connectedCallback();
    this._loadTheme(this.theme);
  }

  updated(changedProps) {
    if (changedProps.has('theme')) {
      this._loadTheme(this.theme);
    }
  }

  // -------------------------------------------------------------------------
  // Theme loading  — injects a <link> into the shadow root
  // -------------------------------------------------------------------------

  _loadTheme(themeName) {
    // Remove old theme link if present
    if (this._themeLink) {
      this._themeLink.remove();
      this._themeLink = null;
    }

    const link = document.createElement('link');
    link.rel = 'stylesheet';
    // highlight.js ships CSS under highlight.js/styles/
    link.href = `https://cdnjs.cloudflare.com/ajax/libs/highlight.js/11.9.0/styles/${themeName}.min.css`;

    // Wait until the root is available
    if (this.shadowRoot) {
      this.shadowRoot.appendChild(link);
    } else {
      this.updateComplete.then(() => {
        this.shadowRoot.appendChild(link);
      });
    }
    this._themeLink = link;
  }

  // -------------------------------------------------------------------------
  // Syntax highlighting
  // -------------------------------------------------------------------------

  _highlight() {
    if (!this.code) return { value: '', language: '' };

    let codeToHighlight = this.code;
    if (this.formatCode) {
      try {
        const langCode = (this.language || 'auto').toLowerCase();
        let formatted = codeToHighlight;
        if (langCode === 'html' || langCode === 'xml') {
          formatted = beautify.html(codeToHighlight, { indent_size: 2, wrap_line_length: 80 });
        } else if (langCode === 'css' || langCode === 'scss' || langCode === 'less') {
          formatted = beautify.css(codeToHighlight, { indent_size: 2 });
        } else {
          // Default to JS for JSON, JS, TS, etc. For unknown languages it might make it weird
          // but we can try basic formatting
          formatted = beautify.js(codeToHighlight, { indent_size: 2 });
        }
        codeToHighlight = formatted;
      } catch (e) {
        // Fallback to original code if formatting fails
      }
    }

    if (this.language && this.language !== 'auto') {
      try {
        const result = hljs.highlight(codeToHighlight, { language: this.language });
        return { value: result.value, language: result.language, formattedCode: codeToHighlight };
      } catch (e) {
        // Unknown language — fall back to auto-detect
      }
    }

    const result = hljs.highlightAuto(codeToHighlight);
    return { value: result.value, language: result.language, formattedCode: codeToHighlight };
  }

  _buildLines(highlightedHtml) {
    if (!this.showLineNumbers) return highlightedHtml;

    const lines = highlightedHtml.split('\n');
    return lines
      .map((line, i) =>
        `<span class="line-number">${i + 1}</span>${line}`
      )
      .join('\n');
  }

  // -------------------------------------------------------------------------
  // Copy to clipboard
  // -------------------------------------------------------------------------

  async _copyCode() {
    try {
      const { formattedCode } = this._highlight();
      await navigator.clipboard.writeText(formattedCode || this.code);
      this._copied = true;
      setTimeout(() => { this._copied = false; }, 2000);
    } catch (e) {
      console.warn('highlightjs-code: clipboard write failed', e);
    }
  }

  // -------------------------------------------------------------------------
  // Styles
  // -------------------------------------------------------------------------

  static get styles() {
    return css`
      :host {
        display: block;
        border-radius: 8px;
        overflow: hidden;
        font-family: 'JetBrains Mono', 'Fira Code', 'Cascadia Code', monospace;
        font-size: 0.875rem;
        line-height: 1.6;
        box-shadow: 0 4px 24px rgba(0,0,0,0.18);
      }

      /* ---- Header bar ---- */
      .header {
        display: flex;
        align-items: center;
        justify-content: space-between;
        padding: 8px 14px;
        background: rgba(0,0,0,0.25);
        backdrop-filter: blur(4px);
        gap: 8px;
        min-height: 36px;
      }

      .header-left {
        display: flex;
        align-items: center;
        gap: 8px;
      }

      /* macOS-style traffic lights (decorative) */
      .dots {
        display: flex;
        gap: 6px;
      }
      .dot {
        width: 12px;
        height: 12px;
        border-radius: 50%;
      }
      .dot-red    { background: #ff5f57; }
      .dot-yellow { background: #ffbd2e; }
      .dot-green  { background: #28c840; }

      .filename {
        font-size: 0.78rem;
        opacity: 0.7;
        letter-spacing: 0.02em;
        color: inherit;
      }

      .header-right {
        display: flex;
        align-items: center;
        gap: 8px;
      }

      .language-badge {
        font-size: 0.7rem;
        text-transform: uppercase;
        letter-spacing: 0.08em;
        opacity: 0.6;
        padding: 2px 7px;
        border: 1px solid currentColor;
        border-radius: 4px;
      }

      .copy-btn {
        background: none;
        border: 1px solid rgba(255,255,255,0.25);
        border-radius: 5px;
        color: inherit;
        cursor: pointer;
        font-size: 0.72rem;
        padding: 3px 9px;
        opacity: 0.7;
        transition: opacity 0.15s, background 0.15s;
        display: flex;
        align-items: center;
        gap: 5px;
      }
      .copy-btn:hover { opacity: 1; background: rgba(255,255,255,0.1); }
      .copy-btn.copied { opacity: 1; border-color: #4ade80; color: #4ade80; }

      /* ---- Code area ---- */
      .code-wrapper {
        overflow: auto;
      }

      pre {
        margin: 0;
        padding: 18px;
        line-height: 1.5;
      }

      code {
        font-family: inherit;
      }

      /* Line number gutter */
      .line-number {
        display: inline-block;
        user-select: none;
        min-width: 2.5em;
        text-align: right;
        opacity: 0.4;
        margin-right: 16px;
        color: inherit;
      }
    `;
  }

  // -------------------------------------------------------------------------
  // Render
  // -------------------------------------------------------------------------

  render() {
    const { value: highlighted, language: detectedLang } = this._highlight();
    const lang = detectedLang || this.language || '';
    const body = this._buildLines(highlighted);
    const hasHeader = this.filename || this.showLanguageBadge || this.showCopyButton;

    return html`
      ${hasHeader ? html`
        <div class="header">
          <div class="header-left">
            <div class="dots">
              <div class="dot dot-red"></div>
              <div class="dot dot-yellow"></div>
              <div class="dot dot-green"></div>
            </div>
            ${this.filename ? html`<span class="filename">${this.filename}</span>` : ''}
          </div>
          <div class="header-right">
            ${this.showLanguageBadge && lang ? html`
              <span class="language-badge">${lang}</span>
            ` : ''}
            ${this.showCopyButton ? html`
              <button
                class="copy-btn ${this._copied ? 'copied' : ''}"
                @click="${this._copyCode}"
                title="Copy to clipboard"
              >
                ${this._copied
                  ? html`<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="20 6 9 17 4 12"/></svg> Copied`
                  : html`<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="9" y="9" width="13" height="13" rx="2"/><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/></svg> Copy`
                }
              </button>
            ` : ''}
          </div>
        </div>
      ` : ''}

      <div class="code-wrapper">
        <pre><code class="hljs" .innerHTML="${body}"></code></pre>
      </div>
    `;
  }
}

customElements.define('highlightjs-code', HighlightjsCode);
